class Solution {
    public String frequencySort(String s) {
        int[] freq = new int[128];
        for (char c : s.toCharArray()) freq[c]++;

        int[] chars = new int[128];
        for (int i = 0; i < 128; i++) chars[i] = i;

        java.util.Arrays.sort(chars, (a, b) -> freq[b] - freq[a]);

        StringBuilder sb = new StringBuilder(s.length());
        for (int c : chars) {
            int cnt = freq[c];
            while (cnt-- > 0) sb.append((char) c);
        }
        return sb.toString();
    }
}
```
